        abbrTxt:SetJustifyH("LEFT")
        abbrTxt:SetPoint("LEFT", row, "LEFT", 2, 0)
        abbrTxt:SetWidth(ABBR_W)

        -- Item icon
        local iconTex = row:CreateTexture(nil, "ARTWORK")
        iconTex:SetSize(ICON_W, ROW_H - 2)
        iconTex:SetPoint("LEFT", row, "LEFT", ABBR_W + PAD2, 1)
