            arow:SetScript("OnLeave", function()
                GameTooltip:Hide()
                local compTip = ComparisonTooltip1 or ShoppingTooltip1
                if compTip then compTip:Hide() end
            end)
            -- store frame + placeholder for data
            IRR_BIS.altRows[slotId][altRank] = { frame = arow, data = nil }
